import{_ as a,a as d,b as e,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as h,o,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"備援備份與讀取來源切換","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/redundant-backup-and-read-source.md","filePath":"zh-TW/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),n={name:"zh-TW/Other/redundant-backup-and-read-source.md"};function s(p,t,c,b,u,m){return o(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="備援備份與讀取來源切換" tabindex="-1">備援備份與讀取來源切換 <a class="header-anchor" href="#備援備份與讀取來源切換" aria-label="Permalink to &quot;備援備份與讀取來源切換&quot;">​</a></h1><p>備援備份會替已上傳檔案再存一份副本。</p><p>主檔案和備份檔案都可以作為讀取來源，使用者看起來沒有差別；差別只在檔案實際從哪個儲存渠道讀取。</p><h2 id="能做什麼" tabindex="-1">能做什麼 <a class="header-anchor" href="#能做什麼" aria-label="Permalink to &quot;能做什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>說明</th></tr></thead><tbody><tr><td>多存一份檔案</td><td>備份到另一個上傳渠道，降低單一渠道故障風險</td></tr><tr><td>切換讀取來源</td><td>備份成功後，可在主渠道與備份渠道之間切換</td></tr><tr><td>單檔備份</td><td>在檔案詳情裡替單一檔案備份</td></tr><tr><td>批次備份</td><td>在管理頁框選多個檔案後批次備份</td></tr><tr><td>全域備援備份</td><td>在其他設定裡依資料夾批次補備份</td></tr></tbody></table><h2 id="備援備份入口" tabindex="-1">備援備份入口 <a class="header-anchor" href="#備援備份入口" aria-label="Permalink to &quot;備援備份入口&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 其他設定 -&gt; 備援備份</span></span></code></pre></div><p><img src="'+a+'" alt="備援備份截圖" loading="lazy"></p><p>這裡適合替某個資料夾或全部檔案統一補備份。</p><p>備份渠道可以手動選，也可以選自動切換，讓系統自己找合適的備份渠道。</p><h2 id="檔案詳情裡備份" tabindex="-1">檔案詳情裡備份 <a class="header-anchor" href="#檔案詳情裡備份" aria-label="Permalink to &quot;檔案詳情裡備份&quot;">​</a></h2><p>在管理後台打開檔案詳情，可以直接點備份檔案。</p><p><img src="'+d+'" alt="檔案詳情裡備份" loading="lazy"></p><p>這個入口適合臨時替單一重要檔案補備份。</p><p>備份成功後，檔案詳情裡會出現可切換的讀取來源。</p><h2 id="框選批次備份" tabindex="-1">框選批次備份 <a class="header-anchor" href="#框選批次備份" aria-label="Permalink to &quot;框選批次備份&quot;">​</a></h2><p>在管理後台可以框選多個檔案，然後執行批次備份。</p><p><img src="'+e+'" alt="批次備份截圖" loading="lazy"></p><p>框選備份、檔案詳情備份、其他設定裡的備援備份，本質上都是同一套備份功能，只是入口不同。</p><h2 id="備份成功後切換讀取來源" tabindex="-1">備份成功後切換讀取來源 <a class="header-anchor" href="#備份成功後切換讀取來源" aria-label="Permalink to &quot;備份成功後切換讀取來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>讀取來源</th><th>說明</th></tr></thead><tbody><tr><td>主渠道</td><td>從原始上傳渠道讀取檔案</td></tr><tr><td>備份渠道</td><td>從備份渠道讀取檔案</td></tr></tbody></table><p><img src="'+r+'" alt="備份成功後切換讀取來源" loading="lazy"></p><p>切到哪個讀取來源，後續訪問檔案時就優先從那個渠道讀取。</p><h2 id="哪些情況會跳過" tabindex="-1">哪些情況會跳過 <a class="header-anchor" href="#哪些情況會跳過" aria-label="Permalink to &quot;哪些情況會跳過&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情況</th><th>為什麼跳過</th></tr></thead><tbody><tr><td>已經有備份</td><td>不重複備份，避免浪費空間</td></tr><tr><td>主備渠道相同</td><td>備份必須放到另一個渠道才有意義</td></tr><tr><td>沒有可用備份渠道</td><td>目前找不到適合的其他渠道</td></tr></tbody></table><h2 id="主渠道和備份渠道" tabindex="-1">主渠道和備份渠道 <a class="header-anchor" href="#主渠道和備份渠道" aria-label="Permalink to &quot;主渠道和備份渠道&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名稱</th><th>說明</th></tr></thead><tbody><tr><td>主渠道</td><td>檔案第一次上傳時使用的渠道</td></tr><tr><td>備份渠道</td><td>後來透過備援備份產生副本的渠道</td></tr><tr><td>主讀取來源</td><td>目前從主渠道讀取</td></tr><tr><td>備份讀取來源</td><td>目前從備份渠道讀取</td></tr></tbody></table><p>只要備份檔案可用，切到備份讀取來源後，圖片、影片、下載連結都會照常使用。</p><h2 id="刪除檔案時會發生什麼" tabindex="-1">刪除檔案時會發生什麼 <a class="header-anchor" href="#刪除檔案時會發生什麼" aria-label="Permalink to &quot;刪除檔案時會發生什麼&quot;">​</a></h2><p>刪除檔案時，系統會同時刪除主檔案和備份檔案。</p>',30)])])}const k=h(n,[["render",s]]);export{f as __pageData,k as default};
